Using Dash
In Nov25, we had a demo on using Dash to create webapps.






Noteapp.py





This is the script we built.
from dash import Dash, html, dash_table, dcc, callback, Output, Input
import pandas as pd
import seaborn as sns
import plotly.express as px

df = pd.read_csv("datasets/Players2024.csv")

app = Dash()

app.layout = [
    html.Div(children="Players 2024.csv data"),
    dcc.RadioItems(options=df["positions"].unique(), value="Attack", id="radio_button"),
    dash_table.DataTable(data=df.to_dict("records"), page_size=10, id="table"),
    dcc.Graph(figure=sns.relplot(df, x="age", y="height_cm")),
]


@callback(
    Output(component_id="table", component_property="data"),
    Input(component_id="radio_button", component_property="value"),
)
def update_table(position_chosen):
    return df[df["positions"] == position_chosen].to_dict("records")


app.run(debug=True)









Noteapp_fancy.py





This is a nicer looking dashboard demonstrating some of the things you could do to fix up the formatting.
from dash import Dash, html, dash_table, dcc, callback, Output, Input
import pandas as pd
import plotly.express as px
import dash_bootstrap_components as dbc

df = pd.read_csv("datasets/Players2024.csv")

df = df[df["positions"] != "Missing"]
df = df[df["height_cm"] &gt; 100]

app = Dash()

external_stylesheets = [dbc.themes.CERULEAN]
app = Dash(__name__, external_stylesheets=external_stylesheets)

app.layout = dbc.Container(
    [
        dbc.Row(
            [
                html.Div(children="Players2024.csv data"),
            ]
        ),
        dbc.Row(
            [
                dbc.RadioItems(
                    options=df["positions"].unique(), value="Attack", id="radio_button"
                ),
            ]
        ),
        dbc.Row(
            [
                dbc.Col(
                    [
                        dash_table.DataTable(
                            data=None,
                            page_size=10,
                            style_table={"overflowX": "auto"},
                            id="table",
                        ),
                    ],
                    width=6,
                ),
                dbc.Col(
                    [
                        dcc.Graph(figure={}, id="graph"),
                    ],
                    width=6,
                ),
            ]
        ),
    ],
    fluid=True,
)


# Build in the callback(s)
@callback(
    Output(component_id="graph", component_property="figure"),
    Input(component_id="radio_button", component_property="value"),
)
def update_graph(position_chosen):
    position = df[df["positions"] == position_chosen]
    fig = px.scatter(position, "age", "height_cm", range_y=[150, 210])
    return fig


@callback(
    Output(component_id="table", component_property="data"),
    Input(component_id="radio_button", component_property="value"),
)
def update_table(position_chosen):
    return df[df["positions"] == position_chosen].to_dict("records")


if __name__ == "__main__":
    app.run(debug=True)

requests
The requests package lets you send HTTP requests. Typically, these are GET, for getting things, and POST, for sending them.

import requests

r = requests.get("https://uqpug.github.io/")
r

&lt;Response [200]&gt;


Every HTTP request gets a status response. The code 200 means OK, so “&lt;Response [200]&gt;” means it worked.
Our response has a lot of attributes. The main one is r.text

Note - if you’re pulling from an API, usually you’ll get JSON code in response. Don’t use r.text there, use r.json().


